import{_ as r,o as l,c as a,ai as h,j as t,a as i,aq as s}from"./chunks/framework.JvjHW6bA.js";const V=JSON.parse('{"title":"メイン画面の説明","description":"","frontmatter":{},"headers":[],"relativePath":"usage/ui/main.md","filePath":"usage/ui/main.md"}'),o={name:"usage/ui/main.md"},c={class:"stopping-icon"},d={xmlns:"http://www.w3.org/2000/svg",viewBox:"0 0 53.333333333333336 53.333333333333336",style:{transform:"rotate(calc(-90deg))"},width:"20",height:"20"};function x(w,e,n,p,g,f){return l(),a("div",null,[e[5]||(e[5]=h('<h1 id="メイン画面の説明" tabindex="-1">メイン画面の説明 <a class="header-anchor" href="#メイン画面の説明" aria-label="Permalink to “メイン画面の説明”">​</a></h1><p><img src="'+s+'" alt="alt text"></p><h2 id="上部ヘッダー" tabindex="-1">上部ヘッダー <a class="header-anchor" href="#上部ヘッダー" aria-label="Permalink to “上部ヘッダー”">​</a></h2><h3 id="_1-時計" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">1</text></svg> 時計 <a class="header-anchor" href="#_1-時計" aria-label="Permalink to “1 時計”">​</a></h3><p>コンピューターの時計を秒単位で表示します。<br> ソフトにフォーカスがない（ショートカットキーが効かない状態）にあると、赤い背景で表示されます。</p><h3 id="_2-カーソルのあるキューのタイトル" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">2</text></svg> カーソルのあるキューのタイトル <a class="header-anchor" href="#_2-カーソルのあるキューのタイトル" aria-label="Permalink to “2 カーソルのあるキューのタイトル”">​</a></h3><p>現在カーソルがあるキューのキュー番号と名前を&quot;・&quot;で繋げたものを表示します。<br> リモート操作時はカーソルがあるキューが表示されており、選択されているキューではないことに注意が必要です。</p><h3 id="_3-カーソルのあるキューのノート" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">3</text></svg> カーソルのあるキューのノート <a class="header-anchor" href="#_3-カーソルのあるキューのノート" aria-label="Permalink to “3 カーソルのあるキューのノート”">​</a></h3><p>現在カーソルがあるキューのノートを表示します。</p><h3 id="_4-カーソルのあるキューの操作" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">4</text></svg> カーソルのあるキューの操作 <a class="header-anchor" href="#_4-カーソルのあるキューの操作" aria-label="Permalink to “4 カーソルのあるキューの操作”">​</a></h3><p>現在カーソルのあるキューについて、停止、実行、一時停止・再開・読み込みを制御できます。</p><h3 id="_5-新規キューの追加ボタン" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">5</text></svg> 新規キューの追加ボタン <a class="header-anchor" href="#_5-新規キューの追加ボタン" aria-label="Permalink to “5 新規キューの追加ボタン”">​</a></h3><p>新たなキューを追加するボタンです。</p><p>左から</p><ul><li>音声、待機、フェードキュー</li><li>グループキュー</li><li>開始、停止、一時停止、読み込みキュー</li></ul><p>です。</p><h2 id="キューリスト" tabindex="-1">キューリスト <a class="header-anchor" href="#キューリスト" aria-label="Permalink to “キューリスト”">​</a></h2><h3 id="_6-カーソル位置" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">6</text></svg> カーソル位置 <a class="header-anchor" href="#_6-カーソル位置" aria-label="Permalink to “6 カーソル位置”">​</a></h3><p>現在のカーソルがあるキューの行に&quot;➡&quot;アイコンを表示します。<br> また、この列をクリックすることで、任意のキューにカーソルを設定できます。</p><h3 id="_7-キューの実行状態" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">7</text></svg> キューの実行状態 <a class="header-anchor" href="#_7-キューの実行状態" aria-label="Permalink to “7 キューの実行状態”">​</a></h3>',20)),t("ul",null,[e[2]||(e[2]=t("li",null,[t("svg",{xmlns:"http://www.w3.org/2000/svg",viewBox:"0 0 24 24",width:"20",height:"20"},[t("title",null,"play"),t("path",{d:"M8,5.14V19.14L19,12.14L8,5.14Z",fill:"#4CAF50"})]),i(" 実行中")],-1)),e[3]||(e[3]=t("li",null,[t("svg",{xmlns:"http://www.w3.org/2000/svg",viewBox:"0 0 24 24",width:"20",height:"20"},[t("title",null,"pause"),t("path",{d:"M14,19H18V5H14M6,19H10V5H6V19Z",fill:"#FB8C00"})]),i(" 一時停止")],-1)),t("li",null,[t("span",c,[(l(),a("svg",d,[...e[0]||(e[0]=[t("circle",{class:"v-progress-circular__underlay",fill:"transparent",cx:"50%",cy:"50%",r:"20","stroke-width":"13.333333333333334","stroke-dasharray":"125.66370614359172","stroke-dashoffset":"0"},null,-1),t("circle",{class:"v-progress-circular__overlay",fill:"transparent",cx:"50%",cy:"50%",r:"20","stroke-width":"13.333333333333334","stroke-dasharray":"125.66370614359172","stroke-dashoffset":"125.66370614359172px"},null,-1)])]))]),e[1]||(e[1]=i(" 停止中",-1))]),e[4]||(e[4]=t("li",null,[t("svg",{xmlns:"http://www.w3.org/2000/svg",viewBox:"0 0 24 24",width:"20",height:"20"},[t("title",null,"upload"),t("path",{d:"M9,16V10H5L12,3L19,10H15V16H9M5,20V18H19V20H5Z",fill:"#FB8C00"})]),i(" 読み込み済み")],-1))]),e[6]||(e[6]=h('<h3 id="_8-キューの種類" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">8</text></svg> キューの種類 <a class="header-anchor" href="#_8-キューの種類" aria-label="Permalink to “8 キューの種類”">​</a></h3><ul><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>volume-high</title><path d="M14,3.23V5.29C16.89,6.15 19,8.83 19,12C19,15.17 16.89,17.84 14,18.7V20.77C18,19.86 21,16.28 21,12C21,7.72 18,4.14 14,3.23M16.5,12C16.5,10.23 15.5,8.71 14,7.97V16C15.5,15.29 16.5,13.76 16.5,12M3,9V15H7L12,20V4L7,9H3Z" fill="white"></path></svg> 音声キュー</li><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>timer-sand-empty</title><path d="M6,2V8H6V8L10,12L6,16V16H6V22H18V16H18V16L14,12L18,8V8H18V2H6M16,16.5V20H8V16.5L12,12.5L16,16.5M12,11.5L8,7.5V4H16V7.5L12,11.5Z" fill="white"></path></svg> 待機キュー</li><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>chart-bell-curve-cumulative</title><path d="M4 19V20H22V22H2V2H4V17C7 17 10 15 12.1 11.4C15.1 6.4 18.4 4 22 4V6C19.2 6 16.5 8.1 13.9 12.5C11.3 16.6 7.7 19 4 19Z" fill="white"></path></svg> フェードキュー</li><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>group</title><path d="M1,1V5H2V19H1V23H5V22H19V23H23V19H22V5H23V1H19V2H5V1M5,4H19V5H20V19H19V20H5V19H4V5H5M6,6V14H9V18H18V9H14V6M8,8H12V12H8M14,11H16V16H11V14H14" fill="white"></path></svg> グループキュー</li><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>play-circle-outline</title><path d="M12,20C7.59,20 4,16.41 4,12C4,7.59 7.59,4 12,4C16.41,4 20,7.59 20,12C20,16.41 16.41,20 12,20M12,2A10,10 0 0,0 2,12A10,10 0 0,0 12,22A10,10 0 0,0 22,12A10,10 0 0,0 12,2M10,16.5L16,12L10,7.5V16.5Z" fill="white"></path></svg> 開始キュー</li><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>stop-circle-outline</title><path d="M12,2A10,10 0 0,0 2,12A10,10 0 0,0 12,22A10,10 0 0,0 22,12A10,10 0 0,0 12,2M12,4C16.41,4 20,7.59 20,12C20,16.41 16.41,20 12,20C7.59,20 4,16.41 4,12C4,7.59 7.59,4 12,4M9,9V15H15V9" fill="white"></path></svg> 停止キュー</li><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>pause-circle-outline</title><path d="M13,16V8H15V16H13M9,16V8H11V16H9M12,2A10,10 0 0,1 22,12A10,10 0 0,1 12,22A10,10 0 0,1 2,12A10,10 0 0,1 12,2M12,4A8,8 0 0,0 4,12A8,8 0 0,0 12,20A8,8 0 0,0 20,12A8,8 0 0,0 12,4Z" fill="white"></path></svg> 一時停止キュー</li><li><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>upload-circle-outline</title><path d="M8 17V15H16V17H8M16 10L12 6L8 10H10.5V14H13.5V10H16M12 2C17.5 2 22 6.5 22 12C22 17.5 17.5 22 12 22C6.5 22 2 17.5 2 12C2 6.5 6.5 2 12 2M12 4C7.58 4 4 7.58 4 12C4 16.42 7.58 20 12 20C16.42 20 20 16.42 20 12C20 7.58 16.42 4 12 4Z" fill="white"></path></svg> 読み込みキュー</li></ul><h3 id="_9-キュー番号" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">9</text></svg> キュー番号 <a class="header-anchor" href="#_9-キュー番号" aria-label="Permalink to “9 キュー番号”">​</a></h3><p>キューに設定された番号を表示します。<br><strong>再生される順序とは関係ありません。</strong><br> キューエディタの基本タブや、編集モード時にダブルクリックすることで編集できます。<br> 数値だけでなく、文字列も使用することができます。</p><h3 id="_10-キューの名前" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="14pt">10</text></svg> キューの名前 <a class="header-anchor" href="#_10-キューの名前" aria-label="Permalink to “10 キューの名前”">​</a></h3><p>キューに設定された名称を表示します。<br> 初期状態ではキューの種類に応じて適切なキュー名が自動で設定されます。<br> キューエディタの基本タブや、編集モード時にダブルクリックすることで編集できます。</p><h3 id="時間表示部分" tabindex="-1">時間表示部分 <a class="header-anchor" href="#時間表示部分" aria-label="Permalink to “時間表示部分”">​</a></h3><h4 id="_11-キューのpre-wait" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="14pt">11</text></svg> キューのPre-Wait <a class="header-anchor" href="#_11-キューのpre-wait" aria-label="Permalink to “11 キューのPre-Wait”">​</a></h4><p>キューに設定されたPre-Waitを表示します。<br> Pre-Waitはキューが実行されるまでの待機時間を表します。<br> キューエディタの基本タブや、編集モード時にダブルクリックすることで編集できます。</p><p>キューが実行前待機中である場合は待機の進捗が表示されます。</p><h4 id="_12-キューの所要時間" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="14pt">12</text></svg> キューの所要時間 <a class="header-anchor" href="#_12-キューの所要時間" aria-label="Permalink to “12 キューの所要時間”">​</a></h4><p>キューの種類に応じて実行にかかる時間を表示します。<br> キューエディタの基本タブや、編集モード時にダブルクリックすることで編集できます。</p><p>キューが実行中である場合は時間の進捗が表示されます。</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>時間を表示する列のヘッダーにあるアイコンをクリックすることで以下の２つの表示モードを切り替えることができます。</p><ul><li><p><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>alpha-e-box-outline</title><path d="M9,7H15V9H11V11H15V13H11V15H15V17H9V7M3,5A2,2 0 0,1 5,3H19A2,2 0 0,1 21,5V19A2,2 0 0,1 19,21H5C3.89,21 3,20.1 3,19V5M5,5V19H19V5H5Z" fill="white"></path></svg> Elapsed：経過時間モード</p></li><li><p><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>alpha-r-box-outline</title><path d="M9,7H13A2,2 0 0,1 15,9V11C15,11.84 14.5,12.55 13.76,12.85L15,17H13L11.8,13H11V17H9V7M11,9V11H13V9H11M5,3H19A2,2 0 0,1 21,5V19A2,2 0 0,1 19,21H5A2,2 0 0,1 3,19V5A2,2 0 0,1 5,3M5,5V19H19V5H5Z" fill="white"></path></svg> Remain：残り時間モード</p></li></ul></div><hr><h3 id="_13-キューのリピート設定" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="14pt">13</text></svg> キューのリピート設定 <a class="header-anchor" href="#_13-キューのリピート設定" aria-label="Permalink to “13 キューのリピート設定”">​</a></h3><ul><li>音声キューがリピート設定されている場合</li><li>グループキューが&quot;プレイリスト&quot;モードに設定されており、リピート設定されている場合</li></ul><p>にリピートアイコン（<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>repeat</title><path d="M17,17H7V14L3,18L7,22V19H19V13H17M7,7H17V10L21,6L17,2V5H5V11H7V7Z" fill="white"></path></svg>）を表示します。</p><h3 id="_14-キューの連鎖モード設定" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="blue"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="14pt">14</text></svg> キューの連鎖モード設定 <a class="header-anchor" href="#_14-キューの連鎖モード設定" aria-label="Permalink to “14 キューの連鎖モード設定”">​</a></h3><p>連鎖モードが&quot;自動継続&quot;の場合は<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>arrow-down</title><path d="M11,4H13V16L18.5,10.5L19.92,11.92L12,19.84L4.08,11.92L5.5,10.5L11,16V4Z" fill="white"></path></svg><br> 連鎖モードが&quot;自動追従&quot;の場合は<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="20" height="20"><title>arrow-expand-down</title><path d="M22,4V2H2V4H11V18.17L5.5,12.67L4.08,14.08L12,22L19.92,14.08L18.5,12.67L13,18.17V4H22Z" fill="white"></path></svg><br> を表示します。</p><h2 id="サイドパネル" tabindex="-1">サイドパネル <a class="header-anchor" href="#サイドパネル" aria-label="Permalink to “サイドパネル”">​</a></h2><h3 id="_15-実行中のキュー" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="#349e33"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="14pt">15</text></svg> 実行中のキュー <a class="header-anchor" href="#_15-実行中のキュー" aria-label="Permalink to “15 実行中のキュー”">​</a></h3><p>実行中のキューを表示します。<br> キューの番号、名前、経過時間、残り時間、再生中のリピート設定等が表示されます。</p><p>タブを切り替えることでレベルメーター表示に切り替えることができます。</p><h2 id="下部エディタ" tabindex="-1">下部エディタ <a class="header-anchor" href="#下部エディタ" aria-label="Permalink to “下部エディタ”">​</a></h2><p>ここでは、選択したキューについて、様々な設定を変更することができます。</p><h3 id="_16-エディタタブ" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="black" stroke-width="2px" fill="#fff800"></circle><text x="13" y="20" text-anchor="middle" fill="black" font-size="13pt">16</text></svg> エディタタブ <a class="header-anchor" href="#_16-エディタタブ" aria-label="Permalink to “16 エディタタブ”">​</a></h3><p>選択しているキューについて、&quot;基本&quot; タブや、キューの種類に応じて様々な種類のエディタのタブが表示されます。<br> タブをクリックすることでそのエディタを開きます。</p><p>&quot;基本&quot; エディタに関しては<a href="./basic_editor.html">こちらのページ</a>の説明を参照してください。</p><p>それぞれのキューのエディタについてはキューの説明を参照してください。</p><h3 id="_17-エディタ内容" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="black" stroke-width="2px" fill="#fff800"></circle><text x="13" y="20" text-anchor="middle" fill="black" font-size="13pt">17</text></svg> エディタ内容 <a class="header-anchor" href="#_17-エディタ内容" aria-label="Permalink to “17 エディタ内容”">​</a></h3><p>エディタの内容が表示される部分です。キューを選択していない場合は何も表示されません。</p><h2 id="フッター" tabindex="-1">フッター <a class="header-anchor" href="#フッター" aria-label="Permalink to “フッター”">​</a></h2><h3 id="_18-編集・実行モードの切り替え" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="#ff00e8"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="13pt">18</text></svg> 編集・実行モードの切り替え <a class="header-anchor" href="#_18-編集・実行モードの切り替え" aria-label="Permalink to “18 編集・実行モードの切り替え”">​</a></h3><p>編集モードと実行モードを切り替える事ができます。</p><p>実行モードでは、<a href="#_5-新規キューの追加ボタン">キュー追加ボタン</a>、<a href="#下部エディタ">下部エディタ</a>を非表示にします。<br> また、<a href="#キューリスト">キューリスト</a>におけるダブルクリックの編集ができなくなります。</p><h3 id="_19-キューの総数" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="#ff00e8"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="13pt">19</text></svg> キューの総数 <a class="header-anchor" href="#_19-キューの総数" aria-label="Permalink to “19 キューの総数”">​</a></h3><p>リストに含まれるすべてのキューの数を表示します。<br> これはグループキュー内部のキューも含まれます。</p><h3 id="_20-サーバーパネルを開く" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="#ff00e8"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="13pt">20</text></svg> サーバーパネルを開く <a class="header-anchor" href="#_20-サーバーパネルを開く" aria-label="Permalink to “20 サーバーパネルを開く”">​</a></h3><p>リモート操作用のサーバー管理パネルを開きます。</p><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>この機能を利用するにはライセンス認証が必要です。</p></div><h3 id="_21-下部エディタの表示切り替え" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="#ff00e8"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="13pt">21</text></svg> 下部エディタの表示切り替え <a class="header-anchor" href="#_21-下部エディタの表示切り替え" aria-label="Permalink to “21 下部エディタの表示切り替え”">​</a></h3><p>下部エディタの表示・非表示を切り替えます。</p><h3 id="_22-サイドパネルの表示切り替え" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="#ff00e8"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="13pt">22</text></svg> サイドパネルの表示切り替え <a class="header-anchor" href="#_22-サイドパネルの表示切り替え" aria-label="Permalink to “22 サイドパネルの表示切り替え”">​</a></h3><p>サイドパネルの表示・非表示を切り替えます。</p><h3 id="_23-設定画面を開く" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="#ff00e8"></circle><text x="13" y="20" text-anchor="middle" fill="white" font-size="13pt">23</text></svg> 設定画面を開く <a class="header-anchor" href="#_23-設定画面を開く" aria-label="Permalink to “23 設定画面を開く”">​</a></h3><p><a href="./settings.html">設定画面</a>を開きます。</p>',47))])}const b=r(o,[["render",x]]);export{V as __pageData,b as default};
